4	export const todos = sqliteTable("todos", {
5	  id: integer("id").primaryKey({ autoIncrement: true }),
6	  title: text("title").notNull(),
7	  completed: integer("completed").notNull().default(0),
8	  createdAt: text("created_at")
9	    .notNull()
10	    .default(sql`(current_timestamp)`),
11	});
